CREATE TABLE IF NOT EXISTS all_publications (`author` STRING, `title` STRING, `published_date` STRING) WITH ('changelog.mode' = 'upsert', 'key.format' = 'avro-registry', 'value.format' = 'avro-registry', 'kafka.retention.time' = '0', 'scan.bounded.mode' = 'unbounded', 'scan.startup.mode' = 'earliest-offset', 'value.fields-include' = 'all') PRIMARY KEY (`title`) NOT ENFORCED DISTRIBUTED BY HASH(`title`) INTO 6 BUCKETS;